def rodCutting(prices, n):
    dp = [0] * (n + 1)
    for i in range(1, n + 1):
        max_val = -1
        for j in range(i):
            max_val = max(max_val, prices[j] + dp[i - j - 1])
        dp[i] = max_val
    return dp[n]

