def hasCycle(adj: list[list[int]]) -> bool:
    visited = [False] * len(adj)

    def dfs(node, parent):
        visited[node] = True
        for neighbor in adj[node]:
            if not visited[neighbor]:
                if dfs(neighbor, node):
                    return True
            elif neighbor != parent:
                return True
        return False

    for i in range(len(adj)):
        if not visited[i]:
            if dfs(i, -1):
                return True
    return False

