def shortestHops(adj, s):
    n = len(adj)
    hops = [-1] * n
    hops[s] = 0
    queue = [s]
    while queue:
        node = queue.pop(0)
        for neighbor in adj[node]:
            if hops[neighbor] == -1:
                hops[neighbor] = hops[node] + 1
                queue.append(neighbor)
    return hops

