def sift_down(arr: list[int], start: int, end: int) -> None:
    root = start
    while True:
        child = 2 * root + 1
        if child >= end:
            break
        if child + 1 < end and arr[child] > arr[child + 1]:
            child += 1
        if arr[root] <= arr[child]:
            break
        arr[root], arr[child] = arr[child], arr[root]
        root = child

